```class Solution {
public:
    int numSub(string s) {
        int MOD = 1e9 + 7;
        int res = 0, count = 0;
        for (char c : s) {
            if (c == '1') {
                count++;
                res = (res + count) % MOD;
            } else {
                count = 0;
            }
        }
        return res;
    }
};```
